module top_module(
	input [31:0] in,
	output [63:0] out
);parameter KEY = 64'h0123456789ABCDEF;

	reg [63:0] shifted_input;
	reg [63:0] obf_result;

	always @(*) begin
		shifted_input = {in, 4'b0000};
		obf_result = shifted_input + 64'h12345678;
		obf_result = obf_result ^ KEY;
	end

	assign out = obf_result;

endmodule
